const rows = $json.courses ?? [];
return rows.map((c) => ({
  json: {
    id: `nptel-${c.course_id}`,
    title: c.course_name,
    description: c.abstract ?? c.course_name,
    sourceId: 'nptel',
    url: `https://nptel.ac.in/courses/${c.course_id}`,
    subjects: [],
    media: ['video-lectures'],
    level: 'gate',
    authors: c.instructors ?? [],
    institution: c.institute ?? '',
    license: 'CC-BY-SA-4.0',
    licenseUrl: 'https://creativecommons.org/licenses/by-sa/4.0/',
    gateTopics: [],
    tags: ['video']
  }
}));
